fast_full_mismatch_patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..47eb8864c12d 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4594,7 +4594,22 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantInt::getFalse(Cond->getType());

     Value *X, *Y;
+    if (match(TrueVal, m_One())) {
+      // (X && Y) || Y --> Y (commuted 2 ways)
+      if (match(Cond, m_c_LogicalAnd(m_Value(), m_Specific(FalseVal))))
+        return FalseVal;
+      // Y || (X && Y) --> Y (commuted 2 ways)
+      if (match(FalseVal, m_c_LogicalAnd(m_Specific(Cond), m_Value())))
+        return Cond;
+    }
+
     if (match(FalseVal, m_ZeroInt())) {
+      // (X || Y) && Y --> Y (commuted 2 ways)
+      if (match(Cond, m_c_LogicalOr(m_Value(), m_Specific(TrueVal))))
+        return TrueVal;
+      // Y && (X || Y) --> Y (commuted 2 ways)
+      if (match(TrueVal, m_c_LogicalOr(m_Specific(Cond), m_Value())))
+        return Cond;
       // !(X || Y) && X --> false (commuted 2 ways)
       if (match(Cond, m_Not(m_c_LogicalOr(m_Specific(TrueVal), m_Value()))))
         return ConstantInt::getFalse(Cond->getType());
